// Get data from previous nodes
const calendarEvents = $('Get Calendar Events for Date').all().map(item => item.json);
const requestedDate = $('Extract Availability Request').first().json.appointmentDate;
const requestedTime = $('Extract Availability Request').first().json.appointmentTime;
const duration = $('Extract Availability Request').first().json.duration;
const timeZone = $('Extract Availability Request').first().json.timeZone;
const toolCallId = $('Check Availability Webhook').first().json.body.message.toolCallList[0].id;

// Business hours (customize as needed)
const WORKDAY_START = "09:00";
const WORKDAY_END = "18:00";
const SLOT_DURATION_MINUTES = 30;

// Helper function to format time as HH:MM
function formatTime(date) {
  return date.toLocaleTimeString('en-US', { 
    hour: '2-digit', 
    minute: '2-digit',
    hour12: true,
    timeZone: timeZone 
  });
}

// Generate all possible 30-minute slots for the day
function generateDaySlots(date) {
  const slots = [];
  const [startHour, startMin] = WORKDAY_START.split(':').map(Number);
  const [endHour, endMin] = WORKDAY_END.split(':').map(Number);

  let current = new Date(`${date}T${WORKDAY_START}:00`);
  const end = new Date(`${date}T${WORKDAY_END}:00`);

  while (current < end) {
    const slotEnd = new Date(current.getTime() + SLOT_DURATION_MINUTES * 60 * 1000);
    slots.push({
      start: current.toISOString(),
      end: slotEnd.toISOString(),
      startTime: formatTime(current),
      endTime: formatTime(slotEnd)
    });
    current = slotEnd;
  }

  return slots;
}

// Check if a slot overlaps with any calendar events
function isSlotAvailable(slot, events) {
  const slotStart = new Date(slot.start);
  const slotEnd = new Date(slot.end);

  for (const event of events) {
    const eventStart = new Date(event.start.dateTime);
    const eventEnd = new Date(event.end.dateTime);

    // Check for overlap
    if (slotStart < eventEnd && slotEnd > eventStart) {
      return false;
    }
  }

  return true;
}

// Generate all slots for the requested day
const allSlots = generateDaySlots(requestedDate);

// Filter to only available slots
const availableSlots = allSlots.filter(slot => 
  isSlotAvailable(slot, calendarEvents)
);

// Take first 3 available slots as suggestions
